SELECT AVG(result) AS average_result
FROM results
WHERE material = 'SpecificMaterial';

SELECT COUNT(*) AS total_samplings
FROM samplings
WHERE day_of_week = 'Monday';

SELECT day_of_week, COUNT(sampling_id) AS sampling_count
FROM samplings
GROUP BY day_of_week;

SELECT AVG(result) AS average_result
FROM results
WHERE material = 'Lead';

SELECT COUNT(DISTINCT sampling_id) AS monday_sampling_count
FROM samplings
WHERE day_of_week = 'Monday';

SELECT material, AVG(result) AS average_result
FROM results
GROUP BY material;
